    32→	async findTopCopurchases({
    33→		styleId,
    34→		limit = 4,
    35→		excludeIds = [],
    36→	}: {
    37→		styleId: number;
    38→		limit?: number;
    39→		excludeIds?: number[];
    40→	}): Promise<{ paired_style_id: number; copurchase_count: number }[]> {
    41→		const dto = plainToInstance(FindTopCopurchasesDto, { styleId, limit, excludeIds });
    42→		const errors = await validate(dto);
    43→		if (errors.length > 0) {
    44→			throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
    45→		}
    46→
    47→		try {
    48→			const queryA = this.knexRead(this.tableName)
    49→				.select('style_id_b as paired_style_id', 'copurchase_count')
    50→				.where({ style_id_a: styleId })
    51→				.whereNull('deleted_at');
    52→
    53→			const queryB = this.knexRead(this.tableName)
