    48→			}
    49→
    50→			const mapped = rows.map((row) => ({
    51→				styleIdA: row.style_a_id,
    52→				styleIdB: row.style_b_id,
    53→				copurchaseCount: row.co_purchase_count,
    54→			}));
    55→
    56→			this.logger.log('Truncating existing co-purchase data...');
    57→			await this.styleCopurchasesService.clearExistingData();
