    80→	private setupGracefulShutdown(): void {
    81→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
    82→
    83→		signals.forEach((signal) => {
    84→			process.on(signal, () => {
